static struct surface_t * cursor = NULL;

static struct region_t unlimited_region = {
	.x = 0,
	.y = 0,
	.w = INT_MAX,
	.h = INT_MAX,
};

void xui_cursor(struct xui_context_t * ctx)
{
	struct matrix2d_t m;

	if(!cursor)
		cursor = surface_alloc_from_buf(cursor_png, sizeof(cursor_png));
	matrix2d_init_translate(&m, ctx->mouse.x - 2, ctx->mouse.y - 2);

	xui_push_clip(ctx, &unlimited_region);
	xui_draw_surface(ctx, cursor, &m, 1);
	xui_pop_clip(ctx);
}
